#include<bits/stdc++.h>
using namespace std;
int n,k;
vector<int> mp[100010];
int max1=-1,max2;
int dis[100010],a[100010],dis1[100010],pre[100010];
void dfs1(int x,int fa=-1)
{
    if(dis[x]>max1)
    {
        max1=dis[x];
        max2=x;
    }
    for(int i:mp[x])
    {
        if(i!=fa)
        {
            dis[i]=dis[x]+1;
            dfs1(i,x);
        }
    }
}
void dfs2(int x,int fa=-1)
{
    if(dis[x]>max1)
    {
        max1=dis[x];
        max2=x;
    }
    for(int i:mp[x])
    {
        if(i!=fa)
        {
            pre[i]=x;
            dis[i]=dis[x]+1;
            dfs2(i,x);
        }
    }
}
void dfs3(int x,int fa=-1)
{
    dis1[x]=dis[x];
    for(int i:mp[x])
    {
        if(i!=fa)
        {
            dis[i]=dis[x]+1;
            dfs3(i,x);
            dis1[x]=max(dis1[x],dis1[i]);
        }
    }
}
int main()
{
    scanf("%d%d",&n,&k);
    for(int i=1;i<n;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        mp[u].push_back(v);
        mp[v].push_back(u);
    }
    dfs1(1);
    max1=-1;
    memset(dis,0,sizeof(dis));
    dfs2(max2);
    int b=max2;
    for(int i=1;i<=(max1+1)/2;i++)
    {
        b=pre[b];
    }
    max1=-1;
    memset(dis,0,sizeof(dis));
    dfs3(b);
    for(int i=1;i<=n;i++)
    {
        a[i]=dis1[i]-dis[i];
    }
    int ans=0;
    sort(a+1,a+1+n,greater<int>());
    for(int i=k+1;i<=n;i++)
    {
        ans=max(ans,a[i]+1);
    }
    printf("%d",ans);
    return 0;
}
